      "description": "The date when the invoice payment is due, in YYYY-MM-DD format.",
      "type": "string"
    },
    "vendor": {
      "description": "Information about the vendor or supplier.",
      "type": "object",
      "properties": {
        "name": {
          "description": "Name of the vendor/supplier.",
          "type": "string"
        },
        "address": {
          "description": "Full address of the vendor/supplier.",
          "type": "string"
        },
        "email": {
          "description": "Email address of the vendor/supplier for billing inquiries.",
          "type": "string"
        }
      },
      "required": [
        "name",
        "address"
      ],
      "additionalProperties": false
    },
    "bill_to": {
      "description": "Information about the customer being billed.",
      "type": "object",
      "properties": {
        "name": {
          "description": "Name of the customer/recipient of the invoice.",
          "type": "string"
        },
        "address": {
          "description": "Full billing address of the customer.",
          "type": "string"
        }
      },
      "required": [
        "name",
        "address"
      ],
      "additionalProperties": false
    },
    "line_items": {
      "description": "A list of individual items or services billed.",
      "type": "array",
      "items": {
        "type": "object",
        "properties": {
          "description": {
            "description": "Description of the item or service.",
            "type": "string"
          },
          "quantity": {
            "description": "Number of units for the item.",
            "type": "number"
          },
          "unit_price": {
            "description": "Price per unit of the item.",
            "type": "number"
          },
          "amount": {
            "description": "Total amount for the line item (quantity * unit_price).",
            "type": "number"
          }
        },
        "required": [
          "description",
          "quantity",
          "unit_price",
          "amount"
        ],
        "additionalProperties": false
      }
    },
    "totals": {
      "description": "Summary of all financial totals for the invoice.",
      "type": "object",
      "properties": {
        "subtotal": {
          "description": "Sum of all line item amounts before taxes and discounts.",
          "type": "number"
        },
        "tax_rate": {
          "description": "Applicable tax rate as a decimal (e.g., 0.08875 for 8.875%).",
          "type": "number"
        },
        "tax_amount": {
          "description": "Total amount of tax applied to the invoice.",
          "type": "number"
        },
        "grand_total": {
          "description": "The final total amount due for the invoice, including taxes.",
          "type": "number"
        }
      },
      "required": [
        "subtotal",
        "grand_total"
      ],
      "additionalProperties": false
    },
    "payment_terms": {
      "description": "Details regarding payment conditions and instructions.",
      "type": "string"
    }
  },
  "required": [
    "invoice_number",
    "issue_date",
    "vendor",
    "bill_to",
    "line_items",
    "totals"
  ],
  "additionalProperties": false
}

